/* REGION_LABELS is now built dynamically inside the component via useRegions() */
const REGION_COLORS = {
  us: C.blue, futures_cme: C.amber, forex: C.green,
  indexes: C.purple, europe_equities: C.blue, crypto: C.amber,
};

function pfColor(pf) {
  if (pf == null) return C.textSecondary;
  if (pf >= 50) return C.green;   // sentinel: no losses
  if (pf >= 2) return C.green;
  if (pf >= 1.5) return '#22C55Ecc';
  if (pf >= 1) return C.amber;
  return C.red;
}

function fmtPF(pf) {
  if (pf == null) return '--';
  if (pf >= 50) return '\u221E';
  return pf.toFixed(2);
}

/* ═══════════════════════════════════════════════════════════════
   HELPERS — formatting, math
   ═══════════════════════════════════════════════════════════════ */
function fmtDollar(v) {
  if (v == null) return '\u2014';
  const abs = Math.abs(v);
  const s = abs >= 1e6 ? `$${(abs / 1e6).toFixed(1)}M` : abs >= 1000 ? `$${(abs / 1000).toFixed(1)}k` : `$${abs.toFixed(0)}`;
  return v < 0 ? `\u2212${s}` : `$${abs >= 1e6 ? (abs / 1e6).toFixed(1) + 'M' : abs >= 1000 ? (abs / 1000).toFixed(1) + 'k' : abs.toFixed(0)}`;
}
function fmtDollarSigned(v) {
  if (v == null) return '\u2014';
  const abs = Math.abs(v);
  const s = abs >= 1e6 ? `$${(abs / 1e6).toFixed(1)}M` : abs >= 1000 ? `$${(abs / 1000).toFixed(1)}k` : `$${abs.toFixed(0)}`;
  return v >= 0 ? `+${s}` : `\u2212${s}`;
}
function fmtPct(v, d = 1) { return v != null && !isNaN(v) && isFinite(v) ? `${v >= 0 ? '+' : ''}${v.toFixed(d)}%` : '\u2014'; }

function computeCAGR(startVal, endVal, days) {
  if (!startVal || startVal <= 0 || !days || days <= 0) return 0;
  const years = days / 365.25;
  if (years <= 0) return 0;
  return (Math.pow(endVal / startVal, 1 / years) - 1) * 100;
}

function durationLabel(days) {
  const years = Math.floor(days / 365);
  const months = Math.floor((days % 365) / 30);
  const d = days % 30;
  const parts = [];
  if (years > 0) parts.push(`${years} year${years > 1 ? 's' : ''}`);
  if (months > 0) parts.push(`${months} month${months > 1 ? 's' : ''}`);
  if (d > 0 || parts.length === 0) parts.push(`${d} day${d !== 1 ? 's' : ''}`);
  return parts.join(', ');
}

function formatFullDate(dateStr) {
  if (!dateStr) return '\u2014';
  const d = new Date(dateStr);
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}

/* ═══════════════════════════════════════════════════════════════
   PnL Spark Chart (SVG)
   ═══════════════════════════════════════════════════════════════ */
function PnlSparkSVG({ data, width = 300, height = 60 }) {
  if (!data || data.length < 2) return null;
  const clean = data.filter(v => v != null && isFinite(v));
  if (clean.length < 2) return null;
  const padY = 4;
  const min = Math.min(...clean);
  const max = Math.max(...clean);
  const range = max - min || 1;
  const zeroY = padY + (1 - (0 - min) / range) * (height - padY * 2);
  const points = data.map((v, i) => {
    const x = (i / (data.length - 1)) * width;
    const y = padY + (1 - (v - min) / range) * (height - padY * 2);
    return `${x},${y}`;
  }).join(' ');
  const lastVal = data[data.length - 1];
  const lineColor = lastVal >= 0 ? C.green : C.red;
  return (
    <svg viewBox={`0 0 ${width} ${height}`} style={{ width: '100%', height }}>
      <defs>
        <linearGradient id="pnlGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={lineColor} stopOpacity="0.2" />
          <stop offset="100%" stopColor={lineColor} stopOpacity="0" />
        </linearGradient>
      </defs>
      <line x1="0" y1={zeroY} x2={width} y2={zeroY} stroke={C.border} strokeWidth="0.5" strokeDasharray="3,3" />
      <polygon points={`0,${zeroY} ${points} ${width},${zeroY}`} fill="url(#pnlGrad)" />
      <polyline points={points} fill="none" stroke={lineColor} strokeWidth="1.5" strokeLinejoin="round" />
    </svg>
  );
}

/* ═══════════════════════════════════════════════════════════════
   System Monitor Bar
   ═══════════════════════════════════════════════════════════════ */
function SystemMonitorBar({ health }) {
  const res = health?.system_resources;
  const daemon = health?.daemon;
  if (!res && !daemon) return null;
  const cpu = res?.cpu_pct;
  const mem = res?.memory_pct;
  const daemonUp = daemon?.status === 'running';
  const cpuColor = cpu > 90 ? C.red : cpu > 70 ? C.amber : C.green;
  const memColor = mem > 85 ? C.red : mem > 70 ? C.amber : C.green;
  return (
    <div className={s.monitorBar}>
      <div className={s.daemonDot}>
        <div className={s.statusDot} style={{ background: daemonUp ? C.green : C.red }} />
        <span className={s.daemonLabel} style={{ color: daemonUp ? C.green : C.red }}>DAEMON</span>
      </div>
      <span className={s.monitorLabel}>CPU</span>
      <span className={s.monitorValue} style={{ color: cpuColor }}>{cpu?.toFixed(0)}%</span>
      <span className={s.monitorLabel}>RAM</span>
      <span className={s.monitorValue} style={{ color: memColor }}>{mem?.toFixed(0)}%</span>
      <span className={s.monitorLabel}>Workers</span>
      <span className={s.monitorValue} style={{ color: C.blue }}>{res?.optimal_workers || '--'}/{res?.cpu_count || '--'}</span>
    </div>
  );
}

