/* ═══════════════════════════════════════════════════════════════
   TRADE COUNT VALIDATOR
   ═══════════════════════════════════════════════════════════════ */
function TradeCountWarning({ totalTrades, totalDays }) {
  if (!totalTrades || !totalDays || totalDays <= 0) return null;
  const tradesPerDay = totalTrades / totalDays;
  if (tradesPerDay <= 50) return null;
  return (
    <div className={s.warningBox} style={{ background: `${C.amber}10`, border: `1px solid ${C.amber}33` }}>
      <span className={s.warningIcon} style={{ color: C.amber }}>{'\u26A0'}</span>
      <div>
        <div className={s.warningTitle} style={{ color: C.amber }}>
          Unrealistic trade frequency: {tradesPerDay.toFixed(0)} trades/day
        </div>
        <div className={s.warningBody}>
          {totalTrades.toLocaleString()} trades over {totalDays} days. Realistic range: 5-20 trades/day
          ({Math.round(5 * totalDays).toLocaleString()}-{Math.round(20 * totalDays).toLocaleString()} expected).
          This may indicate the backtest is scanning all signals, not simulating actual execution.
        </div>
      </div>
    </div>
  );
}

