/* ═══════════════════════════════════════════════════════════════
   STRATEGY ROW — Fixed return calculation
   ═══════════════════════════════════════════════════════════════ */
function StrategyRow({ name, s: strat, rank, allocatedCapital }) {
  const wr = strat.win_rate || 0;
  const pf = strat.profit_factor;
  const pnl = strat.total_pnl || 0;
  const stratReturn = allocatedCapital > 0 ? (pnl / allocatedCapital) * 100 : 0;
  const wrColor = wr >= 55 ? C.green : wr >= 50 ? C.amber : C.red;
  const retColor = stratReturn > 0 ? C.green : stratReturn < 0 ? C.red : C.textSecondary;
  const pnlColor = pnl >= 0 ? C.green : C.red;
  const dir = strat.direction || 'long';

  return (
    <div className={s.strategyRow} style={{ borderBottom: `1px solid ${C.border}22` }}>
      <span className={s.rankCell}>{rank}</span>
      <span className={s.nameCell}>
        {name.replace(/_/g, ' ')}
        <AIExplainButton explainType="strategy" refId={name} label="?" style={{ fontSize: 10, padding: '1px 5px' }} />
      </span>
      <span className={s.monoCellSec}>{strat.count}</span>
      <span className={s.monoCellBold} style={{ color: wrColor }}>
        {wr.toFixed(1)}%
      </span>
      <span className={s.monoCellXBold} style={{ color: pfColor(pf) }} title={pf >= 50 ? 'No losses (all trades profitable)' : undefined}>
        {pf == null ? '--' : pf >= 50 ? '\u221E' : pf.toFixed(2)}
      </span>
      <span className={s.monoCellBold} style={{ color: retColor }}>
        {fmtPct(stratReturn)}
      </span>
      <span className={s.monoCellXBold} style={{ color: pnlColor }}>
        {pnl >= 0 ? '+' : ''}${Math.round(pnl).toLocaleString()}
      </span>
      <span className={dir === 'long' ? s.dirLong : s.dirShort}>
        {dir}
      </span>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   REGION PROGRESS ROW
   ═══════════════════════════════════════════════════════════════ */
function RegionProgress({ reg, rp, REGION_LABELS }) {
  const accent = REGION_COLORS[reg] || C.blue;
  const isDone = rp.phase === 'done' || rp.phase === 'empty';
  const pct = rp.pct || 0;
  return (
    <div className={s.regionRow}>
      <div className={s.regionHeader}>
        <div className={s.regionLeft}>
          <div className={s.regionAccent} style={{ background: accent }} />
          <span className={s.regionName} style={{ color: isDone ? C.green : C.textPrimary }}>
            {(REGION_LABELS[reg] || reg).toUpperCase()}
          </span>
          {rp.phase === 'running' && rp.current && (
            <span className={s.regionCurrent}>{rp.current}</span>
          )}
        </div>
        <span className={s.regionRight} style={{ color: isDone ? C.green : C.textPrimary }}>
          {isDone ? 'DONE' : `${(rp.done || 0).toLocaleString()}/${(rp.total_symbols || 0).toLocaleString()}`}
          <span className={s.regionPct}>{pct.toFixed(0)}%</span>
        </span>
      </div>
      <div className={s.progressTrack}>
        <div className={s.progressFill} style={{
          width: `${Math.min(pct, 100)}%`,
          background: isDone ? C.green : accent,
        }} />
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   MAIN DASHBOARD
   ═══════════════════════════════════════════════════════════════ */
export default function BacktestDashboardPage() {
  usePageTitle('Backtest Dashboard');
  const isMobile = useIsMobile();
  const { regions: regionsArr } = useRegions();
  const REGION_LABELS = Object.fromEntries(regionsArr.map(r => [r.key, r.label]));
  const { results, progress, strategies, regionData } = useBacktestData();
  const { health } = useSystemHealth();
  const [expandedRegion, setExpandedRegion] = useState(null);
  const [viewMode, setViewMode] = useState('portfolio');

  const portfolio = results?.portfolio || null;
  const hasPortfolio = !!portfolio;

  // User-configurable settings (persisted in localStorage)
  const [tradeMode, setTradeMode] = useState(() => localStorage.getItem('bt_trade_mode') || 'pct_equity');
  const [tradeSize, setTradeSize] = useState(() => localStorage.getItem('bt_trade_size') || '100');
  const [accountEquity, setAccountEquity] = useState(() => localStorage.getItem('bt_account_equity') || '10000');
  const [riskPct, setRiskPct] = useState(() => localStorage.getItem('bt_risk_pct') || '5');
  const [liveEquity, setLiveEquity] = useState(null);
  const [showConfig, setShowConfig] = useState(false);
  const [bots, setBots] = useState([]);
  const [selectedBot, setSelectedBot] = useState('all');

  // Auto-fetch live equity from IBKR telemetry on mount
  useEffect(() => {
    (async () => {
      const telem = await api('/telemetry/latest');
      if (!telem) return;
      let total = 0;
      const gw = telem.gateway || {};
      for (const [acct, data] of Object.entries(gw)) {
        if (acct === 'All') continue;
        const nlv = data?.net_liquidation || data?.equity?.current || 0;
        if (nlv > 0) total += nlv;
      }
      if (total === 0) {
        for (const [key, val] of Object.entries(telem)) {
          if (val?.payload?.equity?.current) total += val.payload.equity.current;
        }
      }
      if (total > 0) setLiveEquity(total);
    })();
  }, []);

  useEffect(() => {
    (async () => {
      try {
        const data = await api('/bots');
        if (data?.bots) setBots(data.bots);
      } catch {}
    })();
  }, []);

  const effectiveEquity = Number(accountEquity) || liveEquity || 10000;
  const calcDollarsPerTrade = tradeMode === 'pct_equity' && effectiveEquity > 0
    ? Math.round(effectiveEquity * (Number(riskPct) || 5) / 100)
    : null;

  const saveConfig = useCallback(() => {
    localStorage.setItem('bt_trade_mode', tradeMode);
    localStorage.setItem('bt_risk_pct', riskPct);
    const sizeToSave = tradeMode === 'pct_equity'
      ? String(Math.round((Number(accountEquity) || liveEquity || 10000) * (Number(riskPct) || 5) / 100))
      : tradeSize;
    localStorage.setItem('bt_trade_size', sizeToSave);
    localStorage.setItem('bt_account_equity', accountEquity);
    setShowConfig(false);
  }, [tradeMode, tradeSize, accountEquity, riskPct, liveEquity]);

  const useLiveEquity = useCallback(() => {
    if (liveEquity) setAccountEquity(String(Math.round(liveEquity)));
  }, [liveEquity]);

  // Pipeline status polling
  const [pipeline, setPipeline] = useState(null);
  useEffect(() => {
    let active = true;
    const fetchPipeline = async () => {
      try {
        const data = await api('/data/cache/backfill/progress');
        if (active && data?.regions) setPipeline(data.regions);
      } catch {}
    };
    fetchPipeline();
    const iv = setInterval(fetchPipeline, 5000);
    return () => { active = false; clearInterval(iv); };
  }, []);

  const isRunning = progress && progress.phase === 'running';
  const regions = regionData?.regions || {};
  const regionKeys = Object.keys(regions).sort((a, b) => (regions[b].count || 0) - (regions[a].count || 0));

  // ── Equity-scaled results ──
  const startingCapital = Number(accountEquity) || liveEquity || 10000;
  const btShares = results?.trade_config?.size || 100;

  const dollarsPerTrade = useMemo(() => {
    if (tradeMode === 'pct_equity') return startingCapital * (Number(riskPct) || 5) / 100;
    if (tradeMode === 'dollars') return Number(tradeSize) || 10000;
    return null;
  }, [tradeMode, startingCapital, riskPct, tradeSize]);

  // Scale per_signal by entry_price (existing logic, preserved)
  const scaled = useMemo(() => {
    const perSignal = results?.per_signal || [];
    const byStratRaw = results?.by_strategy || {};

    if (!dollarsPerTrade || perSignal.length === 0) {
      return {
        totalPnl: results?.total_pnl ?? 0,
        grossProfit: results?.gross_profit ?? 0,
        grossLoss: results?.gross_loss ?? 0,
        profitFactor: results?.profit_factor ?? null,
        byStrategy: byStratRaw,
        byRegion: regionData?.regions || {},
        perSignalScaled: perSignal,
      };
    }

    const stratAcc = {};
    const regionAcc = {};
    let globalEntrySum = 0, globalEntryCount = 0;

    for (const sig of perSignal) {
      const ep = sig.entry_price;
      if (!ep || ep <= 0) continue;
      globalEntrySum += ep;
      globalEntryCount++;
      const st = sig.strategy;
      if (st) {
        if (!stratAcc[st]) stratAcc[st] = { entrySum: 0, count: 0 };
        stratAcc[st].entrySum += ep;
        stratAcc[st].count++;
      }
      const rg = sig.region;
      if (rg) {
        if (!regionAcc[rg]) regionAcc[rg] = { entrySum: 0, count: 0 };
        regionAcc[rg].entrySum += ep;
        regionAcc[rg].count++;
      }
    }
    const globalAvgEntry = globalEntryCount > 0 ? globalEntrySum / globalEntryCount : 100;

    const perSignalScaled = perSignal.map(sig => {
      const ep = sig.entry_price && sig.entry_price > 0 ? sig.entry_price : globalAvgEntry;
      const scale = dollarsPerTrade / (btShares * ep);
      return { ...sig, pnl: (sig.pnl || 0) * scale, _scale: scale };
    });

    const scaledByStrategy = {};
    for (const [name, sv] of Object.entries(byStratRaw)) {
      const avgEntry = stratAcc[name]
        ? stratAcc[name].entrySum / stratAcc[name].count
        : globalAvgEntry;
      const scale = dollarsPerTrade / (btShares * avgEntry);
      const gp = (sv.gross_profit || 0) * scale;
      const gl = (sv.gross_loss || 0) * scale;
      scaledByStrategy[name] = {
        ...sv,
        total_pnl: Math.round((sv.total_pnl || 0) * scale * 100) / 100,
        gross_profit: Math.round(gp * 100) / 100,
        gross_loss: Math.round(gl * 100) / 100,
        profit_factor: gl > 0 ? Math.round(gp / gl * 100) / 100 : 999.0,
      };
    }

    const scaledByRegion = {};
    for (const [key, d] of Object.entries(regionData?.regions || {})) {
      const avgEntry = regionAcc[key]
        ? regionAcc[key].entrySum / regionAcc[key].count
        : globalAvgEntry;
      const scale = dollarsPerTrade / (btShares * avgEntry);
      const gp = (d.gross_profit || 0) * scale;
      const gl = (d.gross_loss || 0) * scale;
      const scaledStrats = {};
      for (const [sn, sv] of Object.entries(d.strategies || {})) {
        const savg = stratAcc[sn]
          ? stratAcc[sn].entrySum / stratAcc[sn].count
          : avgEntry;
        const ss = dollarsPerTrade / (btShares * savg);
        const sgp = (sv.gross_profit || 0) * ss;
        const sgl = (sv.gross_loss || 0) * ss;
        scaledStrats[sn] = {
          ...sv,
          total_pnl: Math.round((sv.total_pnl || 0) * ss * 100) / 100,
          gross_profit: Math.round(sgp * 100) / 100,
          gross_loss: Math.round(sgl * 100) / 100,
          profit_factor: sgl > 0 ? Math.round(sgp / sgl * 100) / 100 : 999.0,
        };
      }
      scaledByRegion[key] = {
        ...d,
        total_pnl: Math.round((d.total_pnl || 0) * scale * 100) / 100,
        gross_profit: Math.round(gp * 100) / 100,
        gross_loss: Math.round(gl * 100) / 100,
        profit_factor: gl > 0 ? Math.round(gp / gl * 100) / 100 : 999.0,
        strategies: scaledStrats,
      };
    }

    let tp = 0, tgp = 0, tgl = 0;
    for (const sv of Object.values(scaledByStrategy)) {
      tp += sv.total_pnl;
      tgp += sv.gross_profit;
      tgl += sv.gross_loss;
    }

    return {
      totalPnl: Math.round(tp * 100) / 100,
      grossProfit: Math.round(tgp * 100) / 100,
      grossLoss: Math.round(tgl * 100) / 100,
      profitFactor: tgl > 0 ? Math.round(tgp / tgl * 100) / 100 : 999.0,
      byStrategy: scaledByStrategy,
      byRegion: scaledByRegion,
      perSignalScaled,
    };
  }, [results, dollarsPerTrade, btShares, regionData]);

  // ── FIX #1: TIMEFRAME — extract date range from per_signal ──
  const timeframe = useMemo(() => {
    const ps = scaled.perSignalScaled || [];
    if (ps.length === 0) return { dateFrom: null, dateTo: null, totalDays: 0 };
    let minDate = null, maxDate = null;
    for (const sig of ps) {
      const d = sig.signal_date;
      if (!d) continue;
      if (!minDate || d < minDate) minDate = d;
      if (!maxDate || d > maxDate) maxDate = d;
    }
    if (!minDate || !maxDate) return { dateFrom: null, dateTo: null, totalDays: 0 };
    const totalDays = Math.max(1, Math.round((new Date(maxDate) - new Date(minDate)) / 86400000));
    return { dateFrom: minDate, dateTo: maxDate, totalDays };
  }, [scaled.perSignalScaled]);

  // ── Effective signal list: in portfolio mode, only show executed trades ──
  const effectiveSignals = useMemo(() => {
    const ps = scaled.perSignalScaled || [];
    if (hasPortfolio && viewMode === 'portfolio') {
      return ps.filter(sig => sig.portfolio_status === 'executed');
    }
    return ps;
  }, [scaled.perSignalScaled, hasPortfolio, viewMode]);

  // ── FIX #2: CORRECT RETURN CALCULATION ──
  const totalPnl = scaled.totalPnl;
  const profitFactor = scaled.profitFactor;
  const grossProfit = scaled.grossProfit;
  const grossLoss = scaled.grossLoss;
  const totalSignals = results?.total_signals || 0;
  const avgPnlPerTrade = totalSignals > 0 ? totalPnl / totalSignals : 0;

  // Correct return: pnl / starting capital (NOT total capital deployed/turnover)
  const endingEquity = startingCapital + totalPnl;
  const totalReturn = startingCapital > 0 ? (totalPnl / startingCapital) * 100 : 0;
  const cagr = computeCAGR(startingCapital, endingEquity, timeframe.totalDays);

  // ── FIX #6: allocated capital per strategy for return calculation ──
  const numStrategies = Object.keys(scaled.byStrategy).length || 1;
  const allocatedCapitalPerStrategy = startingCapital / numStrategies;

  // ── FIX #7: ANNUAL BREAKDOWN — uses effectiveSignals (portfolio-filtered in portfolio mode) ──
  const annualData = useMemo(() => {
    const ps = effectiveSignals;
    if (ps.length === 0) return [];
    const sorted = [...ps]
      .filter(sig => sig.pnl != null && sig.signal_date)
      .sort((a, b) => (a.signal_date || '').localeCompare(b.signal_date || ''));

    const byYear = {};
    for (const sig of sorted) {
      const year = parseInt(sig.signal_date.slice(0, 4));
      if (!byYear[year]) byYear[year] = { year, pnl: 0, trades: 0, wins: 0 };
      // In portfolio mode, use portfolio_net_pnl for accurate cost-adjusted P&L
      byYear[year].pnl += (hasPortfolio && viewMode === 'portfolio' && sig.portfolio_net_pnl != null)
        ? sig.portfolio_net_pnl : (sig.pnl || 0);
      byYear[year].trades++;
      const dir = sig.direction || 'long';
      const ret = sig.post_return || 0;
      const isWin = (dir === 'long' && ret > 0) || (dir === 'short' && ret < 0);
      if (isWin) byYear[year].wins++;
    }

    // Compute start equity per year (cumulative)
    const years = Object.values(byYear).sort((a, b) => a.year - b.year);
    let runningEquity = startingCapital;
    for (const y of years) {
      y.startEquity = runningEquity;
      y.winRate = y.trades > 0 ? (y.wins / y.trades) * 100 : 0;
      y.pnl = Math.round(y.pnl);
      runningEquity += y.pnl;
    }
    return years;
  }, [effectiveSignals, startingCapital, hasPortfolio, viewMode]);

  // Cumulative PnL curve — uses effectiveSignals (portfolio-filtered in portfolio mode)
  const pnlCurve = useMemo(() => {
    const ps = effectiveSignals;
    if (ps.length === 0) return [];
    const sorted = [...ps]
      .filter(sig => sig.pnl != null)
      .sort((a, b) => (a.signal_date || '').localeCompare(b.signal_date || ''));
    let cumulative = 0;
    const curve = [];
    const step = Math.max(1, Math.floor(sorted.length / 300));
    for (let i = 0; i < sorted.length; i += step) {
      for (let j = (i === 0 ? 0 : i - step + 1); j <= i && j < sorted.length; j++) {
        cumulative += (hasPortfolio && viewMode === 'portfolio' && sorted[j].portfolio_net_pnl != null)
          ? sorted[j].portfolio_net_pnl : (sorted[j].pnl || 0);
      }
      curve.push(cumulative);
    }
    return curve;
  }, [effectiveSignals, hasPortfolio, viewMode]);

  // Top strategies sorted by PF
  const globalStrategies = useMemo(() => {
    return Object.entries(scaled.byStrategy)
      .sort((a, b) => (b[1].profit_factor || 0) - (a[1].profit_factor || 0));
  }, [scaled.byStrategy]);

  const filteredStrategies = useMemo(() => {
    if (selectedBot === 'all') return globalStrategies;
    const bot = bots.find(b => b.bot_name === selectedBot);
    if (!bot || !bot.strategies || bot.strategies.length === 0) return globalStrategies;
    const botStrats = new Set(bot.strategies.map(st => st.toLowerCase()));
    return globalStrategies.filter(([name]) => botStrats.has(name.toLowerCase()));
  }, [globalStrategies, selectedBot, bots]);

  const filteredByRegion = useMemo(() => {
    if (selectedBot === 'all') return scaled.byRegion;
    const bot = bots.find(b => b.bot_name === selectedBot);
    if (!bot || !bot.strategies || bot.strategies.length === 0) return scaled.byRegion;
    const botStrats = new Set(bot.strategies.map(st => st.toLowerCase()));
    const filtered = {};
    for (const [key, d] of Object.entries(scaled.byRegion)) {
      const filteredStrats = {};
      for (const [sn, sv] of Object.entries(d.strategies || {})) {
        if (botStrats.has(sn.toLowerCase())) filteredStrats[sn] = sv;
      }
      if (Object.keys(filteredStrats).length > 0) {
        filtered[key] = { ...d, strategies: filteredStrats };
      }
    }
    return filtered;
  }, [scaled.byRegion, selectedBot, bots]);

  // Advanced metrics: Sharpe, max drawdown, win streak — uses effectiveSignals
  const advancedMetrics = useMemo(() => {
    const ps = effectiveSignals;
    if (ps.length === 0) return { sharpe: null, maxDD: 0, maxDDPct: 0, winStreak: 0, loseStreak: 0, winRate: 0, peakEquity: 0 };
    const sorted = [...ps].filter(sig => sig.pnl != null).sort((a, b) => (a.signal_date || '').localeCompare(b.signal_date || ''));
    let peak = 0, cum = 0, maxDD = 0, peakEquity = 0, wins = 0, curW = 0, curL = 0, bestW = 0, worstL = 0;
    const rets = [];
    for (const sig of sorted) {
      const pnl = (hasPortfolio && viewMode === 'portfolio' && sig.portfolio_net_pnl != null)
        ? sig.portfolio_net_pnl : (sig.pnl || 0);
      const dir = sig.direction || 'long';
      const ret = sig.post_return || 0;
      const isWin = (dir === 'long' && ret > 0) || (dir === 'short' && ret < 0);
      cum += pnl;
      if (cum > peak) peak = cum;
      const dd = peak - cum;
      if (dd > maxDD) maxDD = dd;
      const portfolioVal = startingCapital + cum;
      if (portfolioVal > peakEquity) peakEquity = portfolioVal;
      rets.push(pnl);
      if (isWin) { wins++; curW++; curL = 0; if (curW > bestW) bestW = curW; }
      else { curL++; curW = 0; if (curL > worstL) worstL = curL; }
    }
    const maxDDPct = peakEquity > 0 ? (maxDD / peakEquity * 100) : 0;
    let sharpe = null;
    if (rets.length > 1) {
      const mean = rets.reduce((a, b) => a + b, 0) / rets.length;
      const std = Math.sqrt(rets.reduce((a, b) => a + (b - mean) ** 2, 0) / (rets.length - 1));
      if (std > 0) sharpe = (mean / std) * Math.sqrt(252);
    }
    return { sharpe, maxDD, maxDDPct, peakEquity, winStreak: bestW, loseStreak: worstL, winRate: sorted.length > 0 ? wins / sorted.length * 100 : 0 };
  }, [effectiveSignals, startingCapital, hasPortfolio, viewMode]);

  // Determine loading, error, and data for LoadingState and ExportBar
  const loading = !results && !progress;
  const error = false;
  const dataArray = filteredStrategies;
  const hasData = dataArray && dataArray.length > 0;

  return (
    <LoadingState loading={loading} error={error} empty={!hasData} emptyMessage='No data available' type='table'>
      <div className={s.page}>
        {/* Bot filter */}
        {bots.length > 0 && (
          <div className={s.botFilterRow}>
            <span className={s.botFilterLabel}>Bot</span>
            <select
              value={selectedBot}
              onChange={(e) => setSelectedBot(e.target.value)}
              className={s.botSelect}
            >
              <option value="all">All Bots</option>
              {bots.map(b => (
                <option key={b.bot_name} value={b.bot_name}>
                  {(b.display_name || b.bot_name).toUpperCase()}
                </option>
              ))}
            </select>
          </div>
        )}

        {/* ExportBar above the strategies table */}
        <ExportBar data={dataArray} filename='export' />

        {/* Example strategies table */}
        <div className={s.strategiesCard}>
          {filteredStrategies.map(([name, strat], idx) => (
            <StrategyRow key={name} name={name} s={strat} rank={idx + 1} allocatedCapital={allocatedCapitalPerStrategy} />
          ))}
        </div>

        {/* Other components and content */}
        <RegulatoryDisclaimer compact />
      </div>
    </LoadingState>
  );
}
